package com.google.gson.internal;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.*;

class JsonReaderInternalAccessTest {

    @Test
    void testPromoteNameToValue_invokesWithoutException() throws Exception {
        // Use reflection to get the INSTANCE field
        Field instanceField = JsonReaderInternalAccess.class.getDeclaredField("INSTANCE");
        instanceField.setAccessible(true);
        JsonReaderInternalAccess instance = (JsonReaderInternalAccess) instanceField.get(null);

        assertNotNull(instance, "JsonReaderInternalAccess.INSTANCE should not be null");

        JsonReader jsonReader = new JsonReader(null);

        // Since promoteNameToValue is abstract, the actual INSTANCE implementation is expected to be non-abstract
        // Just call the method and verify it does not throw IOException
        assertDoesNotThrow(() -> instance.promoteNameToValue(jsonReader));
    }
}
